add("ar","A2","Zaman","حالا","hemen şimdi","kalıp","أحتاج هذا حالا.","Buna hemen şimdi ihtiyacım var.");
add("ar","A2","Sayılar","القليل من","birkaç tane","kalıp","لدي القليل من الأسئلة.","Birkaç sorum var.");
